fig = uifigure('Name', 'Dobot Magician Lite', 'Position', [100 100 700 600]); %[output:74ae2938]
ax = uiaxes(fig, "Position", [10 250 450 350]); %[output:74ae2938]
title(ax, "Joint Positions"); %[output:74ae2938]
xlabel(ax, 'X'); %[output:74ae2938]
ylabel(ax, 'Y'); %[output:74ae2938]
zlabel(ax, 'Z'); %[output:74ae2938]
lim = [-0.3 0.3];
ax.XLim = lim; %[output:74ae2938]
ax.YLim = lim; %[output:74ae2938]
ax.ZLim = lim; %[output:74ae2938]


origin = plot3(ax, 0, 0, 0, 'bo', MarkerFaceColor='b'); %[output:74ae2938]
hold(ax, 'on'); %[output:74ae2938]
joint2 = plot3(ax, 0.1, 0.1, 0.1, 'go', MarkerFaceColor='g'); %[output:74ae2938]
end_effector = plot3(ax, 0.2, 0.2, 0, 'ro', MarkerFaceColor='r'); %[output:74ae2938]
hold(ax, 'on'); %[output:74ae2938]
grid(ax, 'on'); %[output:74ae2938]
grid(ax, 'minor'); %[output:74ae2938]

panel = uipanel(fig, Position=[0 0 500 200]); %[output:74ae2938]
grd = uigridlayout(panel, [4 2]); %[output:74ae2938]
grd.ColumnWidth = {20, '1x'}; %[output:74ae2938]

theta1Label = uilabel(grd); %[output:74ae2938]
theta1Label.Interpreter = 'latex'; %[output:74ae2938]
theta1Label.Text = '$\theta_1'; %[output:74ae2938]

theta1 = uislider(grd); %[output:74ae2938]
theta1.Limits = [-175 175]; %[output:74ae2938]

theta2Label = uilabel(grd); %[output:74ae2938]
theta2Label.Interpreter = 'latex'; %[output:74ae2938]
theta2Label.Text = '$\theta_2'; %[output:74ae2938]
theta2 = uislider(grd); %[output:74ae2938]
theta2.Limits = [-175 175]; %[output:74ae2938]


theta3Label = uilabel(grd); %[output:74ae2938]
theta3Label.Interpreter = 'latex'; %[output:74ae2938]
theta3Label.Text = '$\theta_3'; %[output:74ae2938]
theta3 = uislider(grd); %[output:74ae2938]
theta3.Limits = [-175 175]; %[output:74ae2938]

theta4Label = uilabel(grd); %[output:74ae2938]
theta4Label.Interpreter = 'latex'; %[output:74ae2938]
theta4Label.Text = '$\theta_4'; %[output:74ae2938]
theta4 = uislider(grd); %[output:74ae2938]
theta4.Limits = [-175 175]; %[output:74ae2938]

thetas = [theta1 theta2 theta3 theta4] %[output:38172097]

theta1.ValueChangedFcn = @(src, event) updatePlots(joint2, end_effector, thetas); %[output:74ae2938]
theta2.ValueChangedFcn = @(src, event) updatePlots(joint2, end_effector, thetas); %[output:74ae2938]
theta3.ValueChangedFcn = @(src, event) updatePlots(joint2, end_effector, thetas); %[output:74ae2938]
theta4.ValueChangedFcn = @(src, event) updatePlots(joint2, end_effector, thetas); %[output:74ae2938]

updatePlots(joint2, end_effector, thetas) %[output:74ae2938]


function updatePlots(joint2, end_effector, thetas)
    th1 = deg2rad(thetas(1).Value);
    th2 = deg2rad(thetas(2).Value);
    th3 = deg2rad(thetas(3).Value);
    th4 = deg2rad(thetas(4).Value);
    a1 = dh_link_to_transformation_matrix(0, pi/2, 0, th1);
    a2 = dh_link_to_transformation_matrix(0.15, 0, 0, th2);
    a3 = dh_link_to_transformation_matrix(0.15, 0, 0, th3);
    ap = dh_link_to_transformation_matrix(0, pi/2, 0, -th2 - th3); % passive link to keep the end effector parallel to the ground
    a4 = dh_link_to_transformation_matrix(0, 0, 0, th4); 
    T02 = a1 * a2;
    T04 = a1 * a2 * a3 * ap * a4; % shows end effector position
    joint2.XData = T02(1,4);
    joint2.YData = T02(2,4);
    joint2.ZData = T02(3,4);

    end_effector.XData = T04(1,4);
    end_effector.YData = T04(2,4);
    end_effector.ZData = T04(3,4);
end


